GameModule = {}
GameModule.MaxModules = 3

function GameModule:initModulesData(player)
    player.equip_modules = player.equip_modules or {}
    player.modules = player.modules or {}
    for _, module in pairs(ModuleConfig.Modules) do
        if module.HasGet then
            local data = {
                Id = module.Id,
                Status = GameGunStore.Status.HAS_GET,
                Chip = 0,
            }
            local c_pos
            for pos = 1, GameModule.MaxModules do
                if player.equip_modules[tostring(pos)] == nil then
                    c_pos = pos
                    break
                end
            end
            if c_pos then
                data.Status = GameGunStore.Status.HAS_USE
                player.equip_modules[tostring(c_pos)] = { Id = module.Id }
            end
            table.insert(player.modules, data)
        end
    end
    self:syncEquipModuleData(player)
end

function GameModule:onBuyModule(player, moduleId)
    local config = ModuleConfig:getModuleById(moduleId)
    if not config then
        return
    end
    local c_module
    for _, module in pairs(player.modules) do
        if module.Id == moduleId then
            c_module = module
        end
    end
    if not c_module then
        c_module = {
            Id = config.Id,
            Status = GameGunStore.Status.NOT_GET,
            Chip = 0,
        }
        table.insert(player.modules, c_module)
    end
    if c_module.Status == GameGunStore.Status.HAS_USE or c_module.Status == GameGunStore.Status.HAS_GET then
        return
    end
    if not GameGunStore:checkHasMoney(player, c_module.Chip, config.PriceType, config.Price) then
        HostApi.sendCommonTip(player.rakssid, "gun.store.no.money.tip")
        return
    end
    if config.PriceType == Define.Money.DIAMOND then
        player:consumeDiamonds(10000 + config.Id, config.Price, Define.BuyModule .. "#" .. config.Id)
        return
    end
    if config.PriceType == Define.Money.GOLD then
        return
    end
    if config.PriceType == Define.Money.MONEY then
        player:subCurrency(config.Price)
        GameModule:onBuyModuleSuccess(player, moduleId)
        return
    end
    if config.PriceType == Define.Money.CHIP then
        for _, module in pairs(player.modules) do
            if module.Id == config.Id then
                module.Chip = module.Chip - config.Price
                GameModule:onBuyModuleSuccess(player, moduleId)
            end
        end
    end
end
function GameModule:onBuyModuleSuccess(player, moduleId)
    local config = ModuleConfig:getModuleById(moduleId)
    if not config then
        return
    end
    for _, module in pairs(player.modules) do
        if module.Id == config.Id then
            module.Status = GameGunStore.Status.HAS_GET
        end
    end
    player.taskController:packingProgressData(player, Define.TaskType.GrowUp.CostCoin, GameMatch.gameType, config.PriceType, config.Price)
    self:syncAllModuleData(player)
end

function GameModule:onEquipModule(player, moduleId)
    local config = ModuleConfig:getModuleById(moduleId)
    if not config then
        return
    end
    local c_pos
    for pos = 1, GameModule.MaxModules do
        if player.equip_modules[tostring(pos)] == nil then
            c_pos = pos
            break
        end
    end
    if not c_pos then
        HostApi.sendCommonTip(player.rakssid, "gun.store.full.module.tip")
        return
    end
    for _, module in pairs(player.modules) do
        if module.Id == config.Id and module.Status == GameGunStore.Status.HAS_GET then
            module.Status = GameGunStore.Status.HAS_USE
            player.equip_modules[tostring(c_pos)] = { Id = module.Id }
            break
        end
    end
    self:syncEquipModuleData(player)
    self:syncAllModuleData(player)
end

function GameModule:onUnloadModule(player, moduleId)
    local config = ModuleConfig:getModuleById(moduleId)
    if not config then
        return
    end
    for _, module in pairs(player.modules) do
        if module.Id == config.Id and module.Status == GameGunStore.Status.HAS_USE then
            module.Status = GameGunStore.Status.HAS_GET
            break
        end
    end
    for pos, equip_module in pairs(player.equip_modules) do
        if equip_module.Id == config.Id then
            player.equip_modules[pos] = nil
            break
        end
    end
    self:syncEquipModuleData(player)
    self:syncAllModuleData(player)
end

function GameModule:onFirstShowModule(player, moduleId)
    local config = ModuleConfig:getModuleById(moduleId)
    if not config then
        return
    end
    for _, module in pairs(player.modules) do
        if module.Id == config.Id then
            if module.Status == GameGunStore.Status.HAS_GET or module.Status == GameGunStore.Status.HAS_USE then
                return
            end
            module.Status = GameGunStore.Status.NOT_GET
            return
        end
    end
    local data = {
        Id = config.Id,
        Status = GameGunStore.Status.NOT_GET,
        Chip = 0
    }
    table.insert(player.modules, data)
end

function GameModule:getModulesInfo(player)
    local result = {}
    for _, config in pairs(ModuleConfig.Modules) do
        local data = {}
        data = self:getOneModuleInfo(player, config.Id)
        table.insert(result, data)
    end
    return result
end

function GameModule:getOneModuleInfo(player, moduleId)
    local config = ModuleConfig:getModuleById(moduleId)
    if not config then
        return
    end
    local result
    for _, module in pairs(player.modules) do
        if config.Id == module.Id then
            result = {
                Id = module.Id,
                Status = module.Status,
                Chip = module.Chip
            }
            break
        end
    end
    if not result then
        result = {
            Id = config.Id,
            Status = GameGunStore.Status.NEW,
            Chip = 0
        }
        if config.UnlockLevel > player.level then
            result.Status = GameGunStore.Status.LOCK
        end
        table.insert(player.modules, result)
    end
    return {
        Id = result.Id,
        Status = result.Status
    }
end

function GameModule:syncEquipModuleData(player)
    if not player.clientPeer then
        return
    end
    local result = {}
    for pos = 1, GameModule.MaxModules do
        local module = player.equip_modules[tostring(pos)]
        if not module then
            table.insert(result, pos .. "-" .. "0")
        else
            table.insert(result, pos .. "-" .. module.Id)
        end
    end
    local data = table.concat(result, ",")
    player.clientPeer:setModuleBlockData(data)

end

function GameModule:syncAllModuleData(player)
    if player == nil then
        return
    end
    local data = self:getModulesInfo(player)
    GamePacketSender:sendPixelGunStoreModuleData(player.rakssid, json.encode(data))
end

function GameModule:isNullEquipModule(player)
    for pos = 1, GameModule.MaxModules do
        local module = player.equip_modules[tostring(pos)]
        if  module then
            return true
        end
    end
    return false
end
return GameModule